export function useIsAdmin() {
  const { isSignedIn, isLoaded } = useUser();
  const q = useQuery({
    queryKey: ["admin", "whoami"],
    queryFn: () => adminApi.whoami(),
    enabled: !!isSignedIn,
    staleTime: 60_000,
  });
  return {
    isLoaded: isLoaded && (!isSignedIn || !q.isLoading),
    isAdmin: !!q.data?.isAdmin,
  };
}

